  ('aboriginal-0a2fc18c-moex-00240', 'aboriginal-0a2fc18c', 'aboriginal-0a2fc18c-moex-111-d3ff7f6b', 'sub-aboriginal-0a2fc18c-03', NULL, 'single_choice', '假設高麗菜的市場均衡價格為一斤10元，如果政府規定高麗菜的交易價格不得低於一斤15元， 下列敘述何者正確？', '["價格管制前，供給量大於需求量", "價格管制前，供給量小於需求量", "價格管制後，供給量大於需求量", "價格管制後，供給量小於需求量"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:42+00:00", "source_pdf_sha1": "7948d6976ec8", "answer_pdf_sha1": "db992a01dd7f", "source_family": "moex-gov-tw", "moex": {"exam_code": "111150", "c": "507", "s": "1111", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "經濟學", "year": "111", "exam_name": "111年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、國際經濟商務人員考試、原住民族考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "經建行政"}'::jsonb, NULL),
  ('aboriginal-0a2fc18c-moex-00241', 'aboriginal-0a2fc18c', 'aboriginal-0a2fc18c-moex-111-d3ff7f6b', 'sub-aboriginal-0a2fc18c-03', NULL, 'single_choice', '假設一個劣等財的價格上升。下列何者正確？', '["替代效果及所得效果都會使此物品的消費量增加", "替代效果及所得效果都會使此物品的消費量減少", "替代效果會使此物品的消費量增加，但所得效果會使此物品的消費量減少", "替代效果會使此物品的消費量減少，但所得效果會使此物品的消費量增加"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:42+00:00", "source_pdf_sha1": "7948d6976ec8", "answer_pdf_sha1": "db992a01dd7f", "source_family": "moex-gov-tw", "moex": {"exam_code": "111150", "c": "507", "s": "1111", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "經濟學", "year": "111", "exam_name": "111年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、國際經濟商務人員考試、原住民族考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "經建行政"}'::jsonb, NULL),
